var userConnection = Get<UserConnection>("UserConnection");
var commonInventoryService = new CommonInventoryService(userConnection);

string itemLocationId = Get<string>("ItemLocationId");
string itemCode = Get<string>("ItemCode");
string userId = "NCCF";
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
	var checkStock = new CheckStock(userConnection);
    var param = new CheckStockRequest();

	if(!string.IsNullOrEmpty(itemLocationId) && !string.IsNullOrEmpty(itemCode) && lineDetailId == Guid.Empty) {
		param = checkStock.GetParam(itemLocationId, itemCode, userId);
	} else if(string.IsNullOrEmpty(itemLocationId) && string.IsNullOrEmpty(itemCode) && lineDetailId != Guid.Empty) {
		param = checkStock.GetParam(lineDetailId);
	} else {
		throw new Exception("Input Param cannot be null or empty");
	}

	var check = commonInventoryService.CheckStock(param).GetAwaiter().GetResult();
	Set("Result", JsonConvert.SerializeObject(check, Formatting.Indented));
} catch(Exception e) {
	Set("Result", e.Message);
}

return true;
